#include<bits/stdc++.h>
using namespace std;
long long s,t;
int main(){
    ios::sync_with_stdio(0);
    cin.tie(0);
    cout.tie(0);
    cin>>s>>t;
    if(s < 0 && t & 1)
        cout<<"YES\n";
    else
        cout<<"NO\n";
    if(t==0)
        s=1;
    if(s%2==0)
        cout<<"NO";
    else
        cout<<"YES";
    return 0;
}
